#!/usr/bin/env python3
"""Block `pnpm test` (vitest watch mode); steer Claude to `pnpm test:ci`."""
import json, re, sys

# Matches `pnpm test` or `pnpm run test` where `test` is the whole script
# token. The lookahead excludes `test:ci`, `test:watch`, `testfoo`, etc.
WATCH_TEST = re.compile(r"\bpnpm\s+(?:run\s+)?test(?![\w:-])")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if WATCH_TEST.search(cmd):
        print(
            "Blocked: `pnpm test` runs vitest in watch mode and hangs until "
            "timeout. Run `pnpm test:ci` (vitest run) for a one-shot test run.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""self-improving-claude/no-unbounded-recursion

PostToolUse(Write|Edit): after a .py file is written, flag any directly
recursive function so it is rewritten iteratively (or proven depth-bounded)
before the session continues.

Reason: a recursive refactor of walk_tree raised RecursionError on a
2000-leaf tree (telemetry 2026-05-22). Python's default limit is ~1000 frames.
"""
import ast
import json
import sys


def find_recursive_functions(tree):
    """Return names of functions that call themselves directly."""
    found = set()

    def visit_fn(node):
        name = node.name
        for sub in ast.walk(node):
            if not isinstance(sub, ast.Call):
                continue
            func = sub.func
            if isinstance(func, ast.Name) and func.id == name:
                found.add(name)
            elif isinstance(func, ast.Attribute) and func.attr == name:
                found.add(name)

    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            visit_fn(node)
    return found


def main():
    try:
        payload = json.load(sys.stdin)
    except Exception:
        return 0

    if payload.get("tool_name", "") not in ("Write", "Edit", "MultiEdit"):
        return 0

    path = (payload.get("tool_input", {}) or {}).get("file_path", "")
    if not path.endswith(".py"):
        return 0

    try:
        with open(path, "r", encoding="utf-8") as fh:
            source = fh.read()
    except OSError:
        return 0

    try:
        tree = ast.parse(source)
    except SyntaxError:
        return 0

    recursive = find_recursive_functions(tree)
    if not recursive:
        return 0

    names = ", ".join(sorted(recursive))
    print(
        f"BLOCKING: {path} defines directly recursive function(s): {names}. "
        "Python's default recursion limit is ~1000 frames, so recursion over a "
        "tree, graph, or any input-sized structure raises RecursionError on "
        "large or deep inputs -- this exact bug hit walk_tree on a 2000-leaf "
        "tree. REQUIRED FOLLOW-UP: rewrite each listed function iteratively "
        "with an explicit stack or queue, OR prove its depth is statically "
        "bounded well under 1000 and state that bound in a comment on the "
        "function. Do not stop until one of these is done.",
        file=sys.stderr,
    )
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a Python file, run `ruff format` to fix
formatting deterministically, then `ruff check` and surface remaining lint
errors. Closes the recurring failure where edits leave mixed-indentation /
style issues that a later `ruff check` rejects."""
import json
import subprocess
import sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    path = (ev.get("tool_input") or {}).get("file_path", "")
    if not path.endswith(".py"):
        return 0

    # Auto-fix formatting (the observed mixed-spaces/tabs failure).
    try:
        subprocess.run(
            ["ruff", "format", path],
            capture_output=True, text=True, timeout=8,
        )
    except Exception:
        return 0  # ruff missing or errored — stay out of the way

    # Surface lint errors that formatting cannot auto-fix.
    try:
        r = subprocess.run(
            ["ruff", "check", path],
            capture_output=True, text=True, timeout=8,
        )
    except Exception:
        return 0
    if r.returncode != 0:
        detail = (r.stdout or r.stderr or "").strip()
        print(
            f"REQUIRED FOLLOW-UP: `ruff check` still fails on {path} after formatting:",
            file=sys.stderr,
        )
        if detail:
            print(detail, file=sys.stderr)
        print(
            "Fix each error, then re-run `ruff check`. Do not stop until it passes.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""self-improving-claude/show-exported-identifier-refs
PostToolUse(Edit|MultiEdit): when an edit renames an exported identifier OR
changes the string-literal value of an exported constant, grep the codebase for
the OLD name/value and feed every remaining reference back to Claude. Closes the
failure mode where callers that import the name -- or hardcode the value -- break
silently after a rename (see the tool-name-constant convention in CLAUDE.md)."""
import json, os, re, subprocess, sys

SRC_EXT = (".ts", ".tsx", ".js", ".jsx", ".mjs", ".cjs")
EXPORT_DEF = re.compile(
    r"export\s+(?:default\s+)?(?:const|let|var|function|class|type|interface|enum)\s+([A-Za-z_$][\w$]*)")
EXPORT_BRACE = re.compile(r"export\s*\{([^}]*)\}")
STR_LIT = re.compile(r"""['"]([^'"\n]+)['"]""")


def names_and_values(text):
    names, vals = set(), set()
    for line in text.splitlines():
        if "export" not in line:
            continue
        for m in EXPORT_DEF.finditer(line):
            names.add(m.group(1))
        for m in EXPORT_BRACE.finditer(line):
            for part in m.group(1).split(","):
                n = part.split(" as ")[0].strip()
                if n:
                    names.add(n)
        for m in STR_LIT.finditer(line):
            vals.add(m.group(1))
    return names, vals


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "") or ""
    if not path.endswith(SRC_EXT):
        return 0
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}]
    old_n, old_v, new_n, new_v = set(), set(), set(), set()
    for e in edits:
        n, v = names_and_values(e.get("old_string", "")); old_n |= n; old_v |= v
        n, v = names_and_values(e.get("new_string", "")); new_n |= n; new_v |= v
    gone = {t for t in (old_n - new_n) | (old_v - new_v) if len(t) >= 3}
    if not gone:
        return 0
    root = os.environ.get("CLAUDE_PROJECT_DIR") or ev.get("cwd") or os.getcwd()
    edited_abs = os.path.abspath(path)
    found = {}
    for tok in sorted(gone):
        try:
            r = subprocess.run(
                ["grep", "-rnwF", "--include=*.ts", "--include=*.tsx", "--include=*.js",
                 "--include=*.jsx", "--include=*.mjs", "--include=*.cjs",
                 "--exclude-dir=node_modules", "--exclude-dir=.git", "--exclude-dir=dist",
                 "--exclude-dir=build", "--", tok, root],
                capture_output=True, text=True, timeout=8)
        except Exception:
            continue
        hits = [l for l in r.stdout.splitlines() if l and not l.startswith(edited_abs + ":")][:20]
        if hits:
            found[tok] = hits
    if not found:
        return 0
    total = sum(len(h) for h in found.values())
    print("REQUIRED FOLLOW-UP: this edit renamed/changed exported token(s) "
          + ", ".join(found) + "; " + str(total)
          + " reference(s) to the OLD name/value remain elsewhere and will break.", file=sys.stderr)
    for tok, hits in found.items():
        print("  [" + tok + "]", file=sys.stderr)
        for h in hits:
            print("    " + h, file=sys.stderr)
    print("Fix each reference above to match the new name/value. "
          "Do not stop until every one is reconciled.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())

