#!/usr/bin/env python3
"""Block git add/commit/stage of a real .env; allow .env.example and template variants."""
import json, os, re, shlex, subprocess, sys

SAFE = {"example", "sample", "template"}
SKIP_VALUE = {"-m", "--message", "-F", "--file", "-C", "--reuse-message"}


def is_env(token):
    base = os.path.basename(token.strip().strip('\'"'))
    if base == ".env":
        return True
    m = re.fullmatch(r"\.env\.([\w-]+)", base)
    return bool(m and m.group(1) not in SAFE)


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not re.search(r"\bgit\b[\s\S]*\b(add|commit|stage)\b", cmd):
        return 0
    try:
        tokens = shlex.split(cmd)
    except Exception:
        tokens = cmd.split()

    is_add = any(t in ("add", "stage") for t in tokens)
    skip = bulk = False
    for t in tokens:
        if skip:
            skip = False
            continue
        if t in SKIP_VALUE:
            skip = True
            continue
        if is_add and t in (".", "-A", "--all"):
            bulk = True
        if is_env(t):
            print(f"BLOCKING: refusing to git-stage `{t}`. CLAUDE.md says never commit a real .env — use .env.example for shared placeholders. Remove it from this command, then proceed. Do not ask.", file=sys.stderr)
            return 2

    if bulk:
        try:
            here = ev.get("cwd") or "."
            if os.path.exists(os.path.join(here, ".env")):
                r = subprocess.run(["git", "-C", here, "check-ignore", "-q", ".env"], timeout=5)
                if r.returncode != 0:
                    print("BLOCKING: a real `.env` exists and is not gitignored; `git add` would stage it (CLAUDE.md: never commit a real .env). Add `.env` to .gitignore first, then proceed. Do not ask.", file=sys.stderr)
                    return 2
        except Exception:
            return 0
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Steer npm/yarn package commands to pnpm (CLAUDE.md: Use pnpm)."""
import json, re, sys

# npm/yarn invoked as a command word: at start, or after a shell separator.
PM = re.compile(r"(?:^|[\n;&|(])\s*(npm|yarn)\b")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    m = PM.search(cmd)
    if m:
        tool = m.group(1)
        print(f"BLOCKING: this project uses pnpm (CLAUDE.md). Re-run with `pnpm` instead of `{tool}` (e.g. `pnpm install`, `pnpm add <pkg>`, `pnpm <script>`). Use the pnpm form, then proceed. Do not ask.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""self-improving-claude/python-static-check-after-edit

PostToolUse hook. After an Edit/Write/MultiEdit to a .py file, statically check
the file and feed any errors back so they get fixed immediately instead of being
handed to the user as finished work. Stdlib syntax check runs always; name-aware
checks (undefined names, unused imports) run when ruff, flake8, or pyflakes is
installed. Reason: Claude wrote `grand_total = total + tax` in invoice.py with
`total` undefined and presented it as done; the user had to catch the bug.
"""
import importlib.util
import json
import shutil
import subprocess
import sys


def run(cmd):
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        return r.returncode, (r.stdout or "") + (r.stderr or "")
    except (OSError, subprocess.SubprocessError):
        return None, ""


def main():
    try:
        data = json.load(sys.stdin)
    except (ValueError, json.JSONDecodeError):
        sys.exit(0)

    path = (data.get("tool_input") or {}).get("file_path", "")
    if not path.endswith(".py"):
        sys.exit(0)

    try:
        with open(path, encoding="utf-8") as fh:
            src = fh.read()
    except OSError:
        sys.exit(0)

    problems = []
    try:
        compile(src, path, "exec")
    except SyntaxError as e:
        problems.append(f"{path}:{e.lineno}: SyntaxError: {e.msg}")

    code, out = 0, ""
    if shutil.which("ruff"):
        code, out = run(["ruff", "check", "--select", "F", "--quiet", path])
    elif shutil.which("flake8"):
        code, out = run(["flake8", "--select=F", path])
    elif importlib.util.find_spec("pyflakes"):
        code, out = run([sys.executable, "-m", "pyflakes", path])
    if code not in (None, 0) and out.strip():
        problems.extend(out.strip().splitlines())

    if problems:
        sys.stderr.write(
            "REQUIRED FOLLOW-UP: static check found errors in " + path
            + ". Fix each error listed below before continuing; do not stop "
            + "and do not ask — correct the code now:\n"
            + "\n".join(problems) + "\n"
        )
        sys.exit(2)
    sys.exit(0)


if __name__ == "__main__":
    main()
